1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsWithMHPCO: number };
27	type Damage = { itemType: string; amount: number };
28	type Incident = { cause: string; damages: Damage[] };
29	type QuoteStep = { op: "quote"; items: Item[] };
30	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
31	type Step = QuoteStep | ClaimStep;
32	type Scenario = { customer: Customer; steps: Step[] };
33	
34	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
35	
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const LOYALTY_YEARS_THRESHOLD = 2;
41	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
42	
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PREMIUM = 60;
49	
50	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
51	
52	const sumByLookup = (items: Item[], table: Record<string, number>): number =>
53	  items.reduce((sum, item) => sum + table[item.type], 0);
54	
55	const groupByType = (items: Item[]): Item[][] =>
56	  Object.values(Object.groupBy(items, (item) => item.type));
57	
58	const basePremiumForGroup = (group: Item[]): number =>
59	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumByLookup(group, BASE_PREMIUMS);
60	
61	const basePremiumFor = (items: Item[]): number =>
62	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
63	
64	type RateRule<T> = { rate: number; applies: (input: T) => boolean };
65	
66	const SURCHARGE_RULES: RateRule<Item>[] = [
67	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
68	  {
69	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	    applies: (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
71	  },
72	];
73	
74	const surchargeForRule = (items: Item[], rule: RateRule<Item>): number =>
75	  items
76	    .filter(rule.applies)
77	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rule.rate, 0);
78	
79	const surchargesFor = (items: Item[]): number =>
80	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
81	
82	type PolicyContext = { customer: Customer; isFollowUp: boolean };
83	
84	const POLICY_DISCOUNT_RULES: RateRule<PolicyContext>[] = [
85	  {
86	    rate: LOYALTY_DISCOUNT_RATE,
87	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
88	  },
89	  {
90	    rate: FOLLOW_UP_DISCOUNT_RATE,
91	    applies: ({ isFollowUp }) => isFollowUp,
92	  },
93	];
94	
95	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
96	  POLICY_DISCOUNT_RULES.filter((rule) => rule.applies(context)).reduce(
97	    (total, rule) => total + base * rule.rate,
98	    0,
99	  );
100	
101	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
102	  const base = basePremiumFor(items);
103	  const surcharges = surchargesFor(items);
104	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
105	  const firstInsurance = base * FIRST_INSURANCE_RATE;
106	  return {
107	    premium: Math.ceil(base + surcharges - discounts + firstInsurance + PROCESSING_FEE),
108	  };
109	};
110	
111	const isFollowUpStep = (index: number): boolean => index > 0;
112	
113	type Policy = { items: Item[]; remainingCap: number };
114	
115	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
116	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
117	
118	const createPolicy = (items: Item[]): Policy => ({
119	  items,
120	  remainingCap: CAP_MULTIPLIER * sumByLookup(items, INSURANCE_VALUES),
121	});
122	
123	const reimbursementFor = (item: Item, amount: number): number =>
124	  enchantmentOf(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
125	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
126	    : amount;
127	
128	const payoutForDamage = (damage: Damage, policy: Policy): number => {
129	  const item = policy.items.find((it) => it.type === damage.itemType);
130	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
131	  return Math.max(0, reimbursement - DEDUCTIBLE);
132	};
133	
134	const countByType = (xs: { type: string }[]): Record<string, number> =>
135	  xs.reduce<Record<string, number>>((acc, x) => {
136	    acc[x.type] = (acc[x.type] ?? 0) + 1;
137	    return acc;
138	  }, {});
139	
140	const validateDamages = (damages: Damage[], items: Item[]): void => {
141	  const damageCounts = countByType(damages.map((d) => ({ type: d.itemType })));
142	  const itemCounts = countByType(items);
143	  for (const [type, count] of Object.entries(damageCounts)) {
144	    if (count > (itemCounts[type] ?? 0)) {
145	      throw new Error(`Damage for "${type}" exceeds insured count`);
146	    }
147	  }
148	};
149	
150	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
151	  validateDamages(incident.damages, policy.items);
152	  const uncappedPayout = incident.damages.reduce(
153	    (sum, damage) => sum + payoutForDamage(damage, policy),
154	    0,
155	  );
156	  const payout = Math.floor(Math.min(uncappedPayout, policy.remainingCap));
157	  policy.remainingCap -= payout;
158	  return { payout, remainingCap: policy.remainingCap };
159	};
160	
161	type StepContext = { customer: Customer; index: number; policies: Policy[] };
162	
163	const STEP_HANDLERS: {
164	  [K in Step["op"]]: (step: Extract<Step, { op: K }>, context: StepContext) => StepResult;
165	} = {
166	  quote: ({ items }, { customer, index, policies }) => {
167	    policies[index] = createPolicy(items);
168	    return quotePremium(items, customer, isFollowUpStep(index));
169	  },
170	  claim: (step, { policies }) => processClaim(policies[step.policy], step.incident),
171	};
172	
173	const runStep = (step: Step, context: StepContext): StepResult =>
174	  (STEP_HANDLERS[step.op] as (s: Step, c: StepContext) => StepResult)(step, context);
175	
176	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
177	  const policies: Policy[] = [];
178	  const results = steps.map((step, index) => runStep(step, { customer, index, policies }));
179	  return { results };
180	};
